const body = $input.first().json.body || {};
const targetId = body.target_invoice_id;
if (!targetId || typeof targetId !== 'string') throw new Error('Missing target_invoice_id');
const uuidRe = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!uuidRe.test(targetId)) throw new Error('Invalid target_invoice_id format (must be uuid)');
return [{ json: { target_invoice_id: targetId, trigger_source: body.trigger_source || 'unknown' } }];

const items = $input.all();
const target_invoice_id = $('Validate Payload').first().json.target_invoice_id;
function skip(reason) { return [{ json: { found: false, target_invoice_id, drive_file_id: '', manually_edited: false, reprocess_attempts: 0, should_reprocess: false, skip_reason: reason } }]; }
if (items.length === 0) return skip('no_supabase_items');
const raw = items[0].json;
const row = Array.isArray(raw) ? raw[0] : raw;
if (!row || !row.id) return skip('row_not_found');
const driveOk = typeof row.drive_file_id === 'string' && row.drive_file_id.length > 0;
const notEdited = row.manually_edited !== true;
const attemptsOk = (row.reprocess_attempts || 0) < 3;
const notReviewed = !(row.review_status === 'revisado' || row.review_status === 'confirmado');
const should_reprocess = driveOk && notEdited && attemptsOk && notReviewed;
let reason = '';
if (!driveOk) reason = 'no_drive_file_id';
else if (!notEdited) reason = 'manually_edited';
else if (!attemptsOk) reason = 'attempts_cap_reached';
else if (!notReviewed) reason = 'already_reviewed';
return [{ json: { found: true, ...row, should_reprocess, skip_reason: reason || null } }];

const ocr = $input.first().json;
// Reprocesador ya pasa por Normalize Invoice que tiene reprocess_attempts del row Supabase
const invoice = $('Normalize Invoice').first().json;

const campos = ocr.campos_finales || {};
const newConfidence = ocr.ai_confidence;
const aiData = { ...campos, ai_provider: ocr.ai_provider, _mistral_discrepancies: ocr._mistral_discrepancies || [], _routing_hints: ocr._routing_hints || {} };

const patchBody = {
  ai_data: aiData,
  ai_confidence: newConfidence,
  reprocess_attempts: (invoice.reprocess_attempts || 0) + 1,
  last_reprocess_at: new Date().toISOString()
};

if (typeof campos.amount_total === 'number') patchBody.amount_total = campos.amount_total;
if (typeof campos.amount_base === 'number') patchBody.amount_base = campos.amount_base;
if (typeof campos.vat_amount === 'number') patchBody.vat_amount = campos.vat_amount;
if (campos.supplier_nif) patchBody.supplier_nif = campos.supplier_nif;
if (campos.supplier_name) patchBody.supplier_name = campos.supplier_name;
if (campos.invoice_number) patchBody.invoice_number = campos.invoice_number;
if (campos.issue_date) patchBody.issue_date = campos.issue_date;
if (campos.due_date) patchBody.due_date = campos.due_date;


// === Project Classifier Agent integration ===
let classifyData = null;
try {
  classifyData = $('Classify Project').first().json;
} catch (e) { classifyData = null; }
const classifyAction = classifyData && classifyData.action ? classifyData.action : null;
if (classifyAction === 'auto_assign' && classifyData.project_id) {
  patchBody.project_id = classifyData.project_id;
  patchBody.proyecto_code = classifyData.project_code || null;
  patchBody.proyecto_confianza = classifyData.confidence || null;
} else if (classifyAction === 'suggest' && classifyData.project_code) {
  patchBody.needs_review = true;
  const sugg = `§PROYECTO_SUGERIDO:${classifyData.project_code}:${Math.round((classifyData.confidence || 0) * 100)}%:${(classifyData.reasoning || '').slice(0, 120)}`;
  patchBody.ai_razones = [...(invoice.ai_razones || []), sugg];
} else if (classifyAction === 'needs_review') {
  patchBody.needs_review = true;
}

return [{ json: { target_invoice_id: invoice.id, patch_body: patchBody, new_confidence: newConfidence } }];

// === Parsear respuesta GPT-4o Vision (V2 — sesión 9/05/2026 noche tarde) ===
//
// Cambios respecto a V1:
// - Spread del `parsed` al item raíz (igual que hace Parsear Visión con Gemini),
//   para que Elegir Mejor Resultado y Preparar Supabase encuentren los campos
//   directamente en `item.X` cuando `usar_vision=false` (path GPT-4o ganador).
// - resultado_filesapi enriquecido con TODOS los campos del parsed (no solo los 12 básicos)
// - Cálculo de confianza por completitud (idéntico a Parsear Visión) si GPT no devuelve confianza
// - Manejo de calidad_imagen y campos_dudosos para alimentar razones de revisión

const openaiResponse = $input.item.json;
// V4 (16/05/2026): drop Parsear Visión try block — '.itemMatching' on a node
// that hasn't executed triggers n8n proxy crash (ExpressionError name read-only),
// JS catch leaks at runner level. Convertir a Visión is direct upstream → pairedItem
// 1:1 → safe. Same pattern Parsear Visión uses successfully.
let originalItem;
try {
  originalItem = $('Convertir a Visión').itemMatching($itemIndex).json;
} catch (e) {
  console.error('[Parsear GPT-4o V4] Convertir a Visión itemMatching failed:', e.message);
  originalItem = $input.item.json || {};
}
const { openai_body, ...originalRest } = originalItem;

const choices = openaiResponse.choices || [];
const rawContent = choices[0]?.message?.content || '{}';

let parsed = {};
try {
  let cleaned = rawContent.trim();
  if (cleaned.startsWith('```')) {
    cleaned = cleaned.replace(/^```[a-z]*\s*/i, '').replace(/\s*```$/, '');
  }
  parsed = JSON.parse(cleaned);
  if (Array.isArray(parsed)) {
    if (parsed.length === 0) {
      parsed = { confianza: 0.1, _parse_error: 'empty_array' };
    } else if (parsed.length === 1) {
      parsed = parsed[0];
    } else {
      // QW3 multi-doc: fan-out downstream
      console.log('[Parsear GPT-4o] MULTI-DOC detected: ' + parsed.length + ' items');
      parsed.__multi_doc = true;
      parsed.__multi_doc_items = parsed.slice();
    }
  }
} catch(e) {
  console.error('[Parsear GPT-4o Visión] Error parsing OpenAI response:', e.message, rawContent.substring(0, 300));
  parsed = { tipo: 'otro', direction: 'recibida', confianza: 0.1, razones: ['Error al parsear respuesta IA GPT-4o'], es_documento: true };
}

if (parsed.es_documento === false) {
  console.log('[Parsear GPT-4o Visión] Saltando: GPT identificó adjunto como no-documento');
  return [];
}

const VALID_TIPOS = ['factura','proforma','rectificativa','abono','otro','presupuesto','albaran','certificado','contrato','nota_simple','escritura','licencia','informe','nomina','modelo_fiscal','seguro','ticket','justificante_pago'];
const tipo = VALID_TIPOS.includes((parsed.tipo||'').toLowerCase()) ? parsed.tipo.toLowerCase() : 'otro';
const direction = ['emitida','recibida'].includes((parsed.direction||'').toLowerCase()) ? parsed.direction.toLowerCase() : 'recibida';

// Confianza GPT-4o: usar la que devuelve GPT, si no inferir por score (mismo patrón que Gemini)
let confianza_num;
const rawConf = parsed.confianza;
if (typeof rawConf === 'number') {
  confianza_num = Math.min(1, Math.max(0, rawConf));
} else if (typeof rawConf === 'string') {
  const m = { 'alta': 0.9, 'media': 0.65, 'baja': 0.3 };
  confianza_num = m[rawConf.toLowerCase()] ?? (parseFloat(rawConf) || 0.3);
} else {
  // Inferir por completitud (idéntico patrón a Parsear Visión)
  const hasEmpresa  = !!(parsed.empresa || parsed.supplier_name || parsed.proveedor);
  const hasNif      = !!(parsed.nif_emisor || parsed.supplier_nif);
  const hasNumero   = !!(parsed.numero_factura || parsed.numero || parsed.number);
  const hasImporte  = !!(parsed.importe_total || parsed.amount_total);
  const hasFecha    = !!(parsed.fecha || parsed.fecha_emision || parsed.issue_date);
  const score = [hasEmpresa, hasNif, hasNumero, hasImporte, hasFecha].filter(Boolean).length;
  confianza_num = score >= 5 ? 0.95 : score === 4 ? 0.85 : score === 3 ? 0.70 : score === 2 ? 0.50 : 0.20;
}

const razones = Array.isArray(parsed.razones) ? parsed.razones.filter(r => typeof r === 'string') : [];

// Calidad y campos dudosos (idéntico a Parsear Visión)
const calidad_imagen = ['alta','media','baja'].includes(parsed.calidad_imagen) ? parsed.calidad_imagen : null;
const tipo_doc_origen = ['pdf_digital','pdf_escaneado','foto','manuscrito','mixto'].includes(parsed.tipo_documento_origen) ? parsed.tipo_documento_origen : null;
const camposDudosos = Array.isArray(parsed.campos_dudosos) ? parsed.campos_dudosos.filter(c => typeof c === 'string') : [];

const confs = {
  importe_total: typeof parsed.confianza_importe_total === 'number' ? parsed.confianza_importe_total : null,
  fecha:         typeof parsed.confianza_fecha === 'number' ? parsed.confianza_fecha : null,
  nif:           typeof parsed.confianza_nif === 'number' ? parsed.confianza_nif : null,
  numero_factura: typeof parsed.confianza_numero_factura === 'number' ? parsed.confianza_numero_factura : null,
};

const razonesCalidad = [];
if (calidad_imagen === 'baja') {
  razonesCalidad.push(`§CALIDAD_BAJA:Documento de baja calidad visual (origen: ${tipo_doc_origen || 'desconocido'}). Revisar números clave manualmente.`);
}
if (tipo_doc_origen === 'manuscrito') {
  razonesCalidad.push(`§MANUSCRITO:Documento escrito a mano. Alto riesgo de error en dígitos. Verificar importes, fechas, NIF.`);
}
const CONF_THRESHOLD = 0.75;
for (const [campo, conf] of Object.entries(confs)) {
  if (conf !== null && conf < CONF_THRESHOLD) {
    const valor = parsed[campo === 'nif' ? 'nif_emisor' : (campo === 'numero_factura' ? 'numero_factura' : (campo === 'importe_total' ? 'importe_total' : 'fecha'))];
    razonesCalidad.push(`§CAMPO_DUDOSO:${campo}:${conf.toFixed(2)}:Valor extraído: ${valor || 'null'}`);
  }
}

const parseImporte = (v) => {
  if (v === null || v === undefined || v === '') return null;
  const n = parseFloat(String(v).replace(/[^0-9.,\-]/g, '').replace(',', '.'));
  return isNaN(n) ? null : n;
};

// PROJECT FIELDS — usar contexto del item original
const proyectos_list = originalRest.proyectos_activos || [];
const validCodes = new Set(proyectos_list.map(p => p.code));
const validateCode = (code) => {
  if (!code || typeof code !== 'string') return null;
  const trimmed = code.trim().toUpperCase();
  if (validCodes.has(trimmed)) return trimmed;
  for (const c of validCodes) { if (c.toUpperCase() === trimmed) return c; }
  return null;
};

const proyecto_code = validateCode(parsed.proyecto_code);
const proyecto_code_sugerido = validateCode(parsed.proyecto_code_sugerido);
const proyecto_confianza = typeof parsed.proyecto_confianza === 'number'
  ? Math.min(1, Math.max(0, parsed.proyecto_confianza)) : 0;
const proyecto_razon = parsed.proyecto_razon || '';

// resultado_filesapi RICO (incluye todos los campos del parsed, igual que resultado_vision)
const resultado_filesapi = {
  ...parsed,
  confianza_files: confianza_num,
  tipo,
  direction,
  concept: parsed.concept || parsed.concepto || null,
  numero: parsed.number || parsed.numero || parsed.numero_factura || null,
  supplier_name: parsed.supplier_name || parsed.empresa || parsed.proveedor || null,
  supplier_nif: parsed.supplier_nif || parsed.nif_emisor || null,
  amount_base: parseImporte(parsed.amount_base ?? parsed.importe_base),
  vat_pct: parsed.vat_pct ?? parsed.iva_porcentaje ?? null,
  vat_amount: parseImporte(parsed.vat_amount ?? parsed.importe_iva ?? parsed.iva_importe),
  amount_total: parseImporte(parsed.amount_total ?? parsed.importe_total),
  issue_date: parsed.issue_date || parsed.fecha_emision || parsed.fecha || null,
  due_date: parsed.due_date || parsed.fecha_vencimiento || null,
};

// === QW3 multi-doc fan-out ===
if (parsed.__multi_doc) {
  const items = parsed.__multi_doc_items;
  return items.map((subParsed, subIdx) => ({
    json: {
      ...originalRest,
      ...subParsed,
      _multi_doc_index: subIdx,
      _multi_doc_count: items.length,
      confianza: typeof subParsed.confianza === 'number' ? subParsed.confianza : 0.6,
      ai_confidence: typeof subParsed.confianza === 'number' ? subParsed.confianza : 0.6,
      _fallback_provider: 'gpt-4o',
      tipo: ['factura','proforma','rectificativa','abono','otro','presupuesto','albaran','certificado','contrato','ticket','justificante_pago'].includes((subParsed.tipo||'').toLowerCase()) ? subParsed.tipo.toLowerCase() : 'otro',
      direction: ['emitida','recibida'].includes((subParsed.direction||'').toLowerCase()) ? subParsed.direction.toLowerCase() : 'recibida',
      nif_emisor: subParsed.nif_emisor || subParsed.supplier_nif || null,
      empresa: subParsed.empresa || subParsed.proveedor || subParsed.supplier_name || null,
      numero_factura: subParsed.numero_factura || subParsed.numero || subParsed.number || '',
      fecha_emision: subParsed.fecha || subParsed.fecha_emision || subParsed.issue_date || '',
      importe_total: typeof subParsed.importe_total === 'number' ? subParsed.importe_total : parseFloat(String(subParsed.importe_total||0).replace(/[^0-9.,\-]/g,'').replace(',','.')) || null,
      es_documento: true,
      proyectos_activos: originalRest.proyectos_activos || [],
      clientes_activos: originalRest.clientes_activos || [],
      quote_to_project: originalRest.quote_to_project || {},
    },
    binary: (function() {
    try { return $('Parsear Visión').itemMatching($itemIndex).binary; }
    catch (e) {
      try { return $('Convertir a Visión').itemMatching($itemIndex).binary; }
      catch (e2) { return $input.item.binary || {}; }
    }
  })(),
    pairedItem: { item: $itemIndex }
  }));
}

return {
  json: {
    // Spread original (proyectos_activos, clientes_activos, etc.)
    ...originalRest,
    // Spread del parsed RAW para que Elegir Mejor / Preparar Supabase encuentre los campos directos
    ...parsed,
    // Resultado estructurado para el path files_api
    resultado_filesapi,
    confianza_num_filesapi: confianza_num,
    _fallback_provider: 'gpt-4o',
    // Campos normalizados (igual que Parsear Visión)
    tipo,
    direction,
    nif_emisor: parsed.nif_emisor || parsed.supplier_nif || null,
    proveedor: parsed.empresa || parsed.proveedor || parsed.supplier_name || '',
    empresa: parsed.empresa || parsed.proveedor || parsed.supplier_name || null,
    numero_factura: parsed.numero_factura || parsed.numero || parsed.number || '',
    fecha_emision: parsed.fecha || parsed.fecha_emision || parsed.issue_date || '',
    fecha_vencimiento: parsed.fecha_vencimiento || parsed.due_date || '',
    iva_porcentaje: parsed.iva_porcentaje != null ? parseFloat(parsed.iva_porcentaje) : (parsed.vat_pct != null ? parseFloat(parsed.vat_pct) : null),
    importe_base: parseImporte(parsed.importe_base ?? parsed.amount_base),
    importe_iva: parseImporte(parsed.iva_importe ?? parsed.importe_iva ?? parsed.vat_amount),
    importe_total: parseImporte(parsed.importe_total ?? parsed.amount_total),
    concepto: parsed.concepto || parsed.concept || '',
    confianza: confianza_num,
    razones,
    ai_confidence: confianza_num,
    es_documento: true,
    proyecto_code,
    proyecto_code_sugerido,
    proyecto_confianza,
    proyecto_razon,
    iban_proveedor: parsed.iban_proveedor || null,
    plazo_pago_dias: parsed.plazo_pago_dias != null ? parseInt(parsed.plazo_pago_dias) || null : null,
    num_pedido: parsed.num_pedido || null,
    retencion_porcentaje: parsed.retencion_porcentaje != null ? parseFloat(parsed.retencion_porcentaje) : null,
    retencion_importe: parsed.retencion_importe != null ? parseFloat(parsed.retencion_importe) : null,
    periodo_facturacion: parsed.periodo_facturacion || null,
    moneda: parsed.moneda || 'EUR',
    nif_receptor: parsed.nif_receptor || null,
    nombre_receptor: parsed.nombre_receptor || null,
    // V3 (sesión 9/05/2026 noche tarde): datos del cliente para tabla 'clients' (emitidas)
    cliente_direccion: parsed.cliente_direccion || null,
    cliente_ciudad: parsed.cliente_ciudad || null,
    cliente_telefono: parsed.cliente_telefono || null,
    cliente_email: parsed.cliente_email || null,
    cliente_tipo: parsed.cliente_tipo || null,
    direccion_emisor: parsed.direccion_emisor || null,
    direccion_obra: parsed.direccion_obra || null,
    forma_pago: parsed.forma_pago || null,
    estado_pago: parsed.estado_pago || null,
    es_rectificativa: parsed.es_rectificativa || false,
    numero_factura_original: parsed.numero_factura_original || null,
    categoria_gasto: parsed.categoria_gasto || null,
    tipo_operacion_iva: parsed.tipo_operacion_iva || null,
    lineas: Array.isArray(parsed.lineas) ? parsed.lineas : [],
    inversion_sujeto_pasivo: parsed.inversion_sujeto_pasivo || false,
    tipo_retencion: parsed.tipo_retencion || null,
    detalles_iva: Array.isArray(parsed.detalles_iva) ? parsed.detalles_iva : null,
    codigo_verificacion: parsed.codigo_verificacion || null,
    num_albaran: parsed.num_albaran || null,
    num_contrato: parsed.num_contrato || null,
    validez_hasta: parsed.validez_hasta || null,
    notas_documento: parsed.notas_documento || null,
    idioma: parsed.idioma || 'es',
    resumen_ia: parsed.resumen_ia || null,
    // Calidad y campos dudosos
    calidad_imagen,
    tipo_documento_origen: tipo_doc_origen,
    confianzas_campos: confs,
    campos_dudosos_lista: camposDudosos,
    _razones_calidad: razonesCalidad,
    // Mantener contexto original
    proyectos_activos: originalRest.proyectos_activos || [],
    clientes_activos: originalRest.clientes_activos || [],
    quote_to_project: originalRest.quote_to_project || {}
  },
  binary: (function() {
    try { return $('Parsear Visión').itemMatching($itemIndex).binary; }
    catch (e) {
      try { return $('Convertir a Visión').itemMatching($itemIndex).binary; }
      catch (e2) { return $input.item.binary || {}; }
    }
  })()
};

// Fix C1 (sesión 9/05/2026): cleaned externo al try para evitar ReferenceError en catch
let cleaned = '';


// Parsea la respuesta de GPT-4o visión.
// Guarda resultado_vision en el item para comparar después con Files API si necesario.

const geminiResponse = $input.item.json;
const originalItem = $('Convertir a Visión').itemMatching($itemIndex).json;

// Etapa C: formato response Gemini = candidates[0].content.parts[0].text
const candidates = geminiResponse.candidates || [];
const parts = candidates[0]?.content?.parts || [];
const rawContent = parts[0]?.text || '{}';

let parsed = {};
try {
  let cleaned = rawContent.trim();
  if (cleaned.startsWith('```')) {
    cleaned = cleaned.replace(/^```[a-z]*\s*/i, '').replace(/\s*```$/, '');
  }
  parsed = JSON.parse(cleaned);
  // === QW3 (15/05/2026 research-validated): Multi-doc fan-out ===
  // Si Gemini devuelve array con >1 item → fan-out N output items.
  // Si array con 1 item → tomar [0] como antes.
  // Si 0 items → marcar como error.
  if (Array.isArray(parsed)) {
    if (parsed.length === 0) {
      parsed = { confianza: 0.1, _parse_error: 'empty_array' };
    } else if (parsed.length === 1) {
      parsed = parsed[0];
    } else {
      // Multi-doc detected: marcar para fan-out downstream
      console.log('[Parsear Visión] MULTI-DOC detected: ' + parsed.length + ' items');
      parsed.__multi_doc = true;
      parsed.__multi_doc_items = parsed.slice();  // copy array
    }
  }
} catch(e) {
  console.error('Error parseando respuesta visión:', e.message, 'rawLen:', cleaned.length);
  // Intento de reparación: si la respuesta se truncó (sin } final), cerrar el JSON
  // a la altura del último campo válido completo
  try {
    let repaired = cleaned;
    // Buscar último '"' antes de quedar abandonado, y cerrar arrays/objetos abiertos
    const lastValidKey = repaired.lastIndexOf(',\n');
    if (lastValidKey > 100) {
      repaired = repaired.substring(0, lastValidKey);
      // Cerrar arrays abiertos contando brackets
      const opens = (repaired.match(/\[/g) || []).length - (repaired.match(/\]/g) || []).length;
      const objs = (repaired.match(/\{/g) || []).length - (repaired.match(/\}/g) || []).length;
      for (let i = 0; i < opens; i++) repaired += ']';
      for (let i = 0; i < objs; i++) repaired += '}';
      parsed = JSON.parse(repaired);
      console.log('[Parsear Visión] JSON truncado reparado OK');
    } else {
      parsed = { confianza: 0.1, _parse_error: 'truncated' };
    }
  } catch(e2) {
    console.error('[Parsear Visión] No pude reparar JSON:', e2.message);
    parsed = { confianza: 0.1, _parse_error: 'unrepairable' };
  }
}

// Calcular conf_vision: usar el explícito si GPT lo dio, si no inferir por campos clave
let conf_vision;

// CASO ESPECIAL: nóminas (lote o individual) y resúmenes contables — campos están en arrays anidados
const _isNominaLote = (parsed.tipo === 'nomina_lote' || parsed.tipo === 'nomina') && Array.isArray(parsed.nominas) && parsed.nominas.length > 0;
const _isResumenNominas = parsed.tipo === 'resumen_nominas' && parsed.resumen_nominas;

if (_isNominaLote) {
  // Promediar confianza por completitud de cada nómina del lote
  const confs = parsed.nominas.map(nom => {
    const has = (k1, k2) => !!(nom[k1] || (k2 && nom[k2]));
    const score = [
      has('empresa_nombre','empresa_cif'),
      has('trabajador_nombre','trabajador_nif'),
      has('total_devengado'),
      has('liquido_a_percibir'),
      has('periodo_desde','periodo_hasta'),
    ].filter(Boolean).length;
    return score >= 5 ? 0.95 : score === 4 ? 0.85 : score === 3 ? 0.70 : 0.50;
  });
  conf_vision = confs.reduce((s,c) => s+c, 0) / confs.length;
  console.log(`[Parsear Visión] nomina_lote detectado: ${parsed.nominas.length} nominas, conf_vision=${conf_vision}`);
} else if (_isResumenNominas) {
  // Confianza alta si tiene los totales clave
  const r = parsed.resumen_nominas;
  const score = [r.empresa_cif, r.periodo_mes, r.periodo_anio, r.total_retribuciones, r.total_liquido].filter(Boolean).length;
  conf_vision = score >= 4 ? 0.95 : 0.70;
  console.log(`[Parsear Visión] resumen_nominas detectado, conf_vision=${conf_vision}`);
} else if (typeof parsed.confidence === 'number') {
  conf_vision = parsed.confidence;
} else if (typeof parsed.confianza === 'number') {
  conf_vision = parsed.confianza;
} else {
  // Inferir confianza por completitud de campos críticos extraídos
  const hasEmpresa  = !!(parsed.empresa || parsed.supplier_name);
  const hasNif      = !!(parsed.nif_emisor || parsed.supplier_nif);
  const hasNumero   = !!(parsed.numero_factura || parsed.numero || parsed.number);
  const hasImporte  = !!(parsed.importe_total || parsed.amount_total);
  const hasFecha    = !!(parsed.fecha || parsed.fecha_emision || parsed.issue_date);
  const score = [hasEmpresa, hasNif, hasNumero, hasImporte, hasFecha].filter(Boolean).length;
  // 5/5 → 0.95 ; 4/5 → 0.85 ; 3/5 → 0.70 ; 2/5 → 0.50 ; <2 → 0.20
  conf_vision = score >= 5 ? 0.95 : score === 4 ? 0.85 : score === 3 ? 0.70 : score === 2 ? 0.50 : 0.20;
  console.log('[Parsear Visión] conf_vision inferido:', conf_vision, '(score', score, '/5)');
}

// ═══════════════�����════════════════════════════════════
// EVALUACIÓN DE CALIDAD Y CONFIANZAS POR CAMPO (añadido 26/04/2026)
// ════════════════════════════════════════════════════
const calidad_imagen = ['alta','media','baja'].includes(parsed.calidad_imagen) ? parsed.calidad_imagen : null;
const tipo_doc_origen = ['pdf_digital','pdf_escaneado','foto','manuscrito','mixto'].includes(parsed.tipo_documento_origen) ? parsed.tipo_documento_origen : null;

const confs = {
  importe_total: typeof parsed.confianza_importe_total === 'number' ? parsed.confianza_importe_total : null,
  fecha:         typeof parsed.confianza_fecha === 'number' ? parsed.confianza_fecha : null,
  nif:           typeof parsed.confianza_nif === 'number' ? parsed.confianza_nif : null,
  numero_factura: typeof parsed.confianza_numero_factura === 'number' ? parsed.confianza_numero_factura : null,
};

const camposDudosos = Array.isArray(parsed.campos_dudosos) ? parsed.campos_dudosos.filter(c => typeof c === 'string') : [];

// Construir razones específicas para insertar en ai_razones más tarde (en Preparar Supabase)
const razonesCalidad = [];
if (calidad_imagen === 'baja') {
  razonesCalidad.push(`§CALIDAD_BAJA:Documento de baja calidad visual (origen: ${tipo_doc_origen || 'desconocido'}). Revisar números clave manualmente.`);
}
if (tipo_doc_origen === 'manuscrito') {
  razonesCalidad.push(`§MANUSCRITO:Documento escrito a mano. Alto riesgo de error en dígitos (3↔5↔8, 0↔6, 1↔7). Verificar importes, fechas, NIF.`);
}
if (tipo_doc_origen === 'mixto') {
  razonesCalidad.push(`§MANUSCRITO:Documento parcialmente manuscrito. Verificar campos rellenados a mano.`);
}
// Confianzas individuales bajas para campos críticos
const CONF_THRESHOLD = 0.75;
for (const [campo, conf] of Object.entries(confs)) {
  if (conf !== null && conf < CONF_THRESHOLD) {
    const valor = parsed[campo === 'nif' ? 'nif_emisor' : (campo === 'numero_factura' ? 'numero_factura' : (campo === 'importe_total' ? 'importe_total' : 'fecha'))];
    razonesCalidad.push(`§CAMPO_DUDOSO:${campo}:${conf.toFixed(2)}:Valor extraído: ${valor || 'null'}`);
  }
}
for (const c of camposDudosos) {
  if (!razonesCalidad.some(r => r.includes(`§CAMPO_DUDOSO:${c}:`))) {
    razonesCalidad.push(`§CAMPO_DUDOSO:${c}:?:Campo marcado como dudoso por GPT (sin valor confianza)`);
  }
}

// Si calidad o algún campo crítico es bajo, ajustar conf_vision al peor (techo de confianza)
let conf_vision_adjusted = conf_vision;
if (calidad_imagen === 'baja' || tipo_doc_origen === 'manuscrito') {
  conf_vision_adjusted = Math.min(conf_vision_adjusted, 0.75);
}
const minCampoConf = Math.min(...Object.values(confs).filter(v => v !== null), 1.0);
if (minCampoConf < 0.7) {
  conf_vision_adjusted = Math.min(conf_vision_adjusted, minCampoConf + 0.05);
}

// Normalizar campos (acepta ambos nombres del prompt)
const resultado_vision = {
  ...parsed,
  confianza_vision: conf_vision,
  tipo: parsed.doc_type || parsed.tipo || 'otro',
  direction: parsed.direction || 'recibida',
  concept: parsed.concept || parsed.concepto || null,
  numero: parsed.number || parsed.numero || null,
  supplier_name: parsed.supplier_name || parsed.proveedor || null,
  supplier_nif: parsed.supplier_nif || parsed.nif_emisor || null,
  amount_base: parsed.amount_base || parsed.importe_base || null,
  vat_pct: parsed.vat_pct || parsed.iva_porcentaje || null,
  vat_amount: parsed.vat_amount || parsed.importe_iva || null,
  amount_total: parsed.amount_total || parsed.importe_total || null,
  issue_date: parsed.issue_date || parsed.fecha_emision || null,
  due_date: parsed.due_date || parsed.fecha_vencimiento || null,
  es_extranjera: parsed.es_extranjera || false,
};

// === PROJECT FIELDS from vision ===
const proyectos_list_v = originalItem.proyectos_activos || [];
const validCodesV = new Set(proyectos_list_v.map(p => p.code));
const validateCodeV = (code) => {
  if (!code || typeof code !== 'string') return null;
  const t = code.trim();
  if (validCodesV.has(t)) return t;
  for (const c of validCodesV) { if (c.toUpperCase() === t.toUpperCase()) return c; }
  return null;
};
const proyecto_code_vision = validateCodeV(parsed.proyecto_code);
const proyecto_code_sugerido_vision = validateCodeV(parsed.proyecto_code_sugerido);
const proyecto_confianza_vision = typeof parsed.proyecto_confianza === 'number'
  ? Math.min(1, Math.max(0, parsed.proyecto_confianza)) : 0;
const proyecto_razon_vision = parsed.proyecto_razon || '';

// === QW3: Multi-doc fan-out ===
if (parsed.__multi_doc) {
  const items = parsed.__multi_doc_items;
  return items.map((subParsed, subIdx) => ({
    json: {
      ...originalItem,
      ...subParsed,
      _multi_doc_index: subIdx,
      _multi_doc_count: items.length,
      conf_vision: typeof subParsed.confianza === 'number' ? subParsed.confianza : 0.6,
      conf_vision_raw: typeof subParsed.confianza === 'number' ? subParsed.confianza : 0.6,
      vision_suficiente: (typeof subParsed.confianza === 'number' ? subParsed.confianza : 0.6) >= 0.80,
      tipo: ['factura','proforma','rectificativa','abono','otro','presupuesto','albaran','certificado','contrato','ticket','justificante_pago'].includes((subParsed.tipo||'').toLowerCase()) ? subParsed.tipo.toLowerCase() : 'otro',
      direction: ['emitida','recibida'].includes((subParsed.direction||'').toLowerCase()) ? subParsed.direction.toLowerCase() : 'recibida',
      nif_emisor: subParsed.nif_emisor || subParsed.supplier_nif || null,
      empresa: subParsed.empresa || subParsed.proveedor || subParsed.supplier_name || null,
      numero_factura: subParsed.numero_factura || subParsed.numero || subParsed.number || '',
      fecha_emision: subParsed.fecha || subParsed.fecha_emision || subParsed.issue_date || '',
      importe_total: typeof subParsed.importe_total === 'number' ? subParsed.importe_total : parseFloat(String(subParsed.importe_total||0).replace(/[^0-9.,\-]/g,'').replace(',','.')) || null,
      es_documento: true,
      proyectos_activos: originalItem.proyectos_activos || [],
      clientes_activos: originalItem.clientes_activos || [],
      quote_to_project: originalItem.quote_to_project || {},
    },
    binary: $('Convertir a Visión').itemMatching($itemIndex).binary,
    pairedItem: { item: $itemIndex }
  }));
}

return {
  json: {
    ...originalItem,
    resultado_vision,
    conf_vision: conf_vision_adjusted,
    conf_vision_raw: conf_vision,
    calidad_imagen,
    tipo_documento_origen: tipo_doc_origen,
    confianzas_campos: confs,
    campos_dudosos_lista: camposDudosos,
    _razones_calidad: razonesCalidad,
    // Si conf >= 0.80, no necesita intento 2
    vision_suficiente: conf_vision >= 0.80,
    proyecto_code_vision: proyecto_code_vision,
    proyecto_code_sugerido_vision: proyecto_code_sugerido_vision,
    proyecto_confianza_vision: proyecto_confianza_vision,
    proyecto_razon_vision: proyecto_razon_vision,
    iban_proveedor: parsed.iban_proveedor || null,
    plazo_pago_dias: parsed.plazo_pago_dias != null ? parseInt(parsed.plazo_pago_dias) || null : null,
    num_pedido: parsed.num_pedido || null,
    retencion_porcentaje: parsed.retencion_porcentaje != null ? parseFloat(parsed.retencion_porcentaje) : null,
    retencion_importe: parsed.retencion_importe != null ? parseFloat(parsed.retencion_importe) : null,
    periodo_facturacion: parsed.periodo_facturacion || null,
    proyectos_activos: originalItem.proyectos_activos || [],
    clientes_activos: originalItem.clientes_activos || [],
    quote_to_project: originalItem.quote_to_project || {}
  },
  binary: $('Convertir a Visión').itemMatching($itemIndex).binary
};

