  binary: geminiBinary
};

// === Construir AI Usage Records (sub-workflow version 18/05/2026) ===
// Sub-workflow only. Recolecta tokens de Gemini + GPT-4o + Mistral (NO GPT-mini, ese vive en parent).
// Output: item con campo `ai_usage_tokens` array para que Sub Output lo exponga al parent.
