};

// Helper Mistral OCR
const extractMistral = () => {
  try {
    const r = $('Llamar Mistral OCR').itemMatching($itemIndex).json;
    const u = r?.usage_info || r?.usage;
    if (!u) return null;
    return {
      provider: 'mistral-ocr',
      model: 'mistral-ocr-latest',
      tokens_input: u.prompt_tokens || u.pages_processed || 0,
      tokens_output: u.completion_tokens || 0,
      context: 'reconcile',
      status: 'success'
    };
  } catch (e) { return null; }
};

const g = extractGemini();
if (g) records.push(g);
const gpt = extractGpt4o();
if (gpt) records.push(gpt);
const m = extractMistral();
if (m) records.push(m);

return { json: { ...item, ai_usage_tokens: records } };

