const candidates = geminiResponse.candidates || [];
const parts = candidates[0]?.content?.parts || [];
const rawContent = parts[0]?.text || '{}';

let parsed = {};
try {
  let cleaned = rawContent.trim();
  if (cleaned.startsWith('```')) {
    cleaned = cleaned.replace(/^```[a-z]*\s*/i, '').replace(/\s*```$/, '');
  }
  parsed = JSON.parse(cleaned);
  // === QW3 (15/05/2026 research-validated): Multi-doc fan-out ===
  // Si Gemini devuelve array con >1 item → fan-out N output items.
  // Si array con 1 item → tomar [0] como antes.
  // Si 0 items → marcar como error.
  if (Array.isArray(parsed)) {
    if (parsed.length === 0) {
      parsed = { confianza: 0.1, _parse_error: 'empty_array' };
    } else if (parsed.length === 1) {
      parsed = parsed[0];
    } else {
      // Multi-doc detected: marcar para fan-out downstream
      console.log('[Parsear Visión] MULTI-DOC detected: ' + parsed.length + ' items');
      parsed.__multi_doc = true;
      parsed.__multi_doc_items = parsed.slice();  // copy array
    }
  }
} catch(e) {
  console.error('Error parseando respuesta visión:', e.message, 'rawLen:', cleaned.length);
  // Intento de reparación: si la respuesta se truncó (sin } final), cerrar el JSON
  // a la altura del último campo válido completo
  try {
    let repaired = cleaned;
    // Buscar último '"' antes de quedar abandonado, y cerrar arrays/objetos abiertos
    const lastValidKey = repaired.lastIndexOf(',\n');
    if (lastValidKey > 100) {
      repaired = repaired.substring(0, lastValidKey);
      // Cerrar arrays abiertos contando brackets
      const opens = (repaired.match(/\[/g) || []).length - (repaired.match(/\]/g) || []).length;
      const objs = (repaired.match(/\{/g) || []).length - (repaired.match(/\}/g) || []).length;
      for (let i = 0; i < opens; i++) repaired += ']';
      for (let i = 0; i < objs; i++) repaired += '}';
      parsed = JSON.parse(repaired);
      console.log('[Parsear Visión] JSON truncado reparado OK');
    } else {
      parsed = { confianza: 0.1, _parse_error: 'truncated' };
    }
  } catch(e2) {
    console.error('[Parsear Visión] No pude reparar JSON:', e2.message);
