  conf_vision = confs.reduce((s,c) => s+c, 0) / confs.length;
  console.log(`[Parsear Visión] nomina_lote detectado: ${parsed.nominas.length} nominas, conf_vision=${conf_vision}`);
} else if (_isResumenNominas) {
  // Confianza alta si tiene los totales clave
  const r = parsed.resumen_nominas;
  const score = [r.empresa_cif, r.periodo_mes, r.periodo_anio, r.total_retribuciones, r.total_liquido].filter(Boolean).length;
  conf_vision = score >= 4 ? 0.95 : 0.70;
  console.log(`[Parsear Visión] resumen_nominas detectado, conf_vision=${conf_vision}`);
} else if (typeof parsed.confidence === 'number') {
  conf_vision = parsed.confidence;
} else if (typeof parsed.confianza === 'number') {
  conf_vision = parsed.confianza;
} else {
  // Inferir confianza por completitud de campos críticos extraídos
  const hasEmpresa  = !!(parsed.empresa || parsed.supplier_name);
  const hasNif      = !!(parsed.nif_emisor || parsed.supplier_nif);
  const hasNumero   = !!(parsed.numero_factura || parsed.numero || parsed.number);
  const hasImporte  = !!(parsed.importe_total || parsed.amount_total);
  const hasFecha    = !!(parsed.fecha || parsed.fecha_emision || parsed.issue_date);
  const score = [hasEmpresa, hasNif, hasNumero, hasImporte, hasFecha].filter(Boolean).length;
  // 5/5 → 0.95 ; 4/5 → 0.85 ; 3/5 → 0.70 ; 2/5 → 0.50 ; <2 → 0.20
  conf_vision = score >= 5 ? 0.95 : score === 4 ? 0.85 : score === 3 ? 0.70 : score === 2 ? 0.50 : 0.20;
  console.log('[Parsear Visión] conf_vision inferido:', conf_vision, '(score', score, '/5)');
}

// ═══════════════�����════════════════════════════════════
// EVALUACIÓN DE CALIDAD Y CONFIANZAS POR CAMPO (añadido 26/04/2026)
// ════════════════════════════════════════════════════
const calidad_imagen = ['alta','media','baja'].includes(parsed.calidad_imagen) ? parsed.calidad_imagen : null;
const tipo_doc_origen = ['pdf_digital','pdf_escaneado','foto','manuscrito','mixto'].includes(parsed.tipo_documento_origen) ? parsed.tipo_documento_origen : null;

const confs = {
  importe_total: typeof parsed.confianza_importe_total === 'number' ? parsed.confianza_importe_total : null,
  fecha:         typeof parsed.confianza_fecha === 'number' ? parsed.confianza_fecha : null,
  nif:           typeof parsed.confianza_nif === 'number' ? parsed.confianza_nif : null,
  numero_factura: typeof parsed.confianza_numero_factura === 'number' ? parsed.confianza_numero_factura : null,
};

const camposDudosos = Array.isArray(parsed.campos_dudosos) ? parsed.campos_dudosos.filter(c => typeof c === 'string') : [];

// Construir razones específicas para insertar en ai_razones más tarde (en Preparar Supabase)
const razonesCalidad = [];
if (calidad_imagen === 'baja') {
  razonesCalidad.push(`§CALIDAD_BAJA:Documento de baja calidad visual (origen: ${tipo_doc_origen || 'desconocido'}). Revisar números clave manualmente.`);
}
if (tipo_doc_origen === 'manuscrito') {
  razonesCalidad.push(`§MANUSCRITO:Documento escrito a mano. Alto riesgo de error en dígitos (3↔5↔8, 0↔6, 1↔7). Verificar importes, fechas, NIF.`);
}
if (tipo_doc_origen === 'mixto') {
  razonesCalidad.push(`§MANUSCRITO:Documento parcialmente manuscrito. Verificar campos rellenados a mano.`);
}
// Confianzas individuales bajas para campos críticos
const CONF_THRESHOLD = 0.75;
for (const [campo, conf] of Object.entries(confs)) {
  if (conf !== null && conf < CONF_THRESHOLD) {
    const valor = parsed[campo === 'nif' ? 'nif_emisor' : (campo === 'numero_factura' ? 'numero_factura' : (campo === 'importe_total' ? 'importe_total' : 'fecha'))];
    razonesCalidad.push(`§CAMPO_DUDOSO:${campo}:${conf.toFixed(2)}:Valor extraído: ${valor || 'null'}`);
  }
}
for (const c of camposDudosos) {
  if (!razonesCalidad.some(r => r.includes(`§CAMPO_DUDOSO:${c}:`))) {
    razonesCalidad.push(`§CAMPO_DUDOSO:${c}:?:Campo marcado como dudoso por GPT (sin valor confianza)`);
  }
}

// Si calidad o algún campo crítico es bajo, ajustar conf_vision al peor (techo de confianza)
let conf_vision_adjusted = conf_vision;
if (calidad_imagen === 'baja' || tipo_doc_origen === 'manuscrito') {
  conf_vision_adjusted = Math.min(conf_vision_adjusted, 0.75);
}
const minCampoConf = Math.min(...Object.values(confs).filter(v => v !== null), 1.0);
if (minCampoConf < 0.7) {
  conf_vision_adjusted = Math.min(conf_vision_adjusted, minCampoConf + 0.05);
}

// Normalizar campos (acepta ambos nombres del prompt)
const resultado_vision = {
  ...parsed,
  confianza_vision: conf_vision,
  tipo: parsed.doc_type || parsed.tipo || 'otro',
  direction: parsed.direction || 'recibida',
  concept: parsed.concept || parsed.concepto || null,
  numero: parsed.number || parsed.numero || null,
  supplier_name: parsed.supplier_name || parsed.proveedor || null,
  supplier_nif: parsed.supplier_nif || parsed.nif_emisor || null,
  amount_base: parsed.amount_base || parsed.importe_base || null,
  vat_pct: parsed.vat_pct || parsed.iva_porcentaje || null,
  vat_amount: parsed.vat_amount || parsed.importe_iva || null,
  amount_total: parsed.amount_total || parsed.importe_total || null,
  issue_date: parsed.issue_date || parsed.fecha_emision || null,
  due_date: parsed.due_date || parsed.fecha_vencimiento || null,
  es_extranjera: parsed.es_extranjera || false,
};

// === PROJECT FIELDS from vision ===
const proyectos_list_v = originalItem.proyectos_activos || [];
const validCodesV = new Set(proyectos_list_v.map(p => p.code));
const validateCodeV = (code) => {
  if (!code || typeof code !== 'string') return null;
  const t = code.trim();
  if (validCodesV.has(t)) return t;
  for (const c of validCodesV) { if (c.toUpperCase() === t.toUpperCase()) return c; }
  return null;
};
const proyecto_code_vision = validateCodeV(parsed.proyecto_code);
const proyecto_code_sugerido_vision = validateCodeV(parsed.proyecto_code_sugerido);
const proyecto_confianza_vision = typeof parsed.proyecto_confianza === 'number'
  ? Math.min(1, Math.max(0, parsed.proyecto_confianza)) : 0;
const proyecto_razon_vision = parsed.proyecto_razon || '';

// === QW3: Multi-doc fan-out ===
if (parsed.__multi_doc) {
  const items = parsed.__multi_doc_items;
  return items.map((subParsed, subIdx) => ({
    json: {
      ...originalItem,
      ...subParsed,
      _multi_doc_index: subIdx,
      _multi_doc_count: items.length,
      conf_vision: typeof subParsed.confianza === 'number' ? subParsed.confianza : 0.6,
      conf_vision_raw: typeof subParsed.confianza === 'number' ? subParsed.confianza : 0.6,
      vision_suficiente: (typeof subParsed.confianza === 'number' ? subParsed.confianza : 0.6) >= 0.80,
      tipo: ['factura','proforma','rectificativa','abono','otro','presupuesto','albaran','certificado','contrato','ticket','justificante_pago'].includes((subParsed.tipo||'').toLowerCase()) ? subParsed.tipo.toLowerCase() : 'otro',
      direction: ['emitida','recibida'].includes((subParsed.direction||'').toLowerCase()) ? subParsed.direction.toLowerCase() : 'recibida',
      nif_emisor: subParsed.nif_emisor || subParsed.supplier_nif || null,
      empresa: subParsed.empresa || subParsed.proveedor || subParsed.supplier_name || null,
      numero_factura: subParsed.numero_factura || subParsed.numero || subParsed.number || '',
      fecha_emision: subParsed.fecha || subParsed.fecha_emision || subParsed.issue_date || '',
      importe_total: typeof subParsed.importe_total === 'number' ? subParsed.importe_total : parseFloat(String(subParsed.importe_total||0).replace(/[^0-9.,\-]/g,'').replace(',','.')) || null,
      es_documento: true,
      proyectos_activos: originalItem.proyectos_activos || [],
      clientes_activos: originalItem.clientes_activos || [],
      quote_to_project: originalItem.quote_to_project || {},
    },
    binary: $('Convertir a Visión').itemMatching($itemIndex).binary,
    pairedItem: { item: $itemIndex }
  }));
}

return {
  json: {
    ...originalItem,
    resultado_vision,
    conf_vision: conf_vision_adjusted,
    conf_vision_raw: conf_vision,
    calidad_imagen,
    tipo_documento_origen: tipo_doc_origen,
    confianzas_campos: confs,
    campos_dudosos_lista: camposDudosos,
    _razones_calidad: razonesCalidad,
    // Si conf >= 0.80, no necesita intento 2
    vision_suficiente: conf_vision >= 0.80,
    proyecto_code_vision: proyecto_code_vision,
    proyecto_code_sugerido_vision: proyecto_code_sugerido_vision,
    proyecto_confianza_vision: proyecto_confianza_vision,
    proyecto_razon_vision: proyecto_razon_vision,
    iban_proveedor: parsed.iban_proveedor || null,
    plazo_pago_dias: parsed.plazo_pago_dias != null ? parseInt(parsed.plazo_pago_dias) || null : null,
    num_pedido: parsed.num_pedido || null,
    retencion_porcentaje: parsed.retencion_porcentaje != null ? parseFloat(parsed.retencion_porcentaje) : null,
    retencion_importe: parsed.retencion_importe != null ? parseFloat(parsed.retencion_importe) : null,
    periodo_facturacion: parsed.periodo_facturacion || null,
    proyectos_activos: originalItem.proyectos_activos || [],
    clientes_activos: originalItem.clientes_activos || [],
    quote_to_project: originalItem.quote_to_project || {}
  },
  binary: $('Convertir a Visión').itemMatching($itemIndex).binary
};

