const gpt = extractGpt4o();
if (gpt) records.push(gpt);
const m = extractMistral();
if (m) records.push(m);

return { json: { ...item, ai_usage_tokens: records } };

const fetchResp = $input.item.json;
const invoice = $('Normalize Invoice').first().json;
const images = fetchResp.images || [];
if (images.length === 0) throw new Error('Fetch and Convert returned 0 images');
const mimeForGpt = 'image/jpeg';
const gemini_body = { contents: [{ parts: images.map(b64 => ({ inline_data: { mime_type: mimeForGpt, data: b64 } })) }] };
const openai_body = images.map(b64 => ({ type: 'image_url', image_url: { url: `data:${mimeForGpt};base64,${b64}` } }));
return { json: {
  ...invoice,
  supabase_id: invoice.id,
  fileName: invoice.original_filename || fetchResp.file_name || 'reprocess.pdf',
  originalFileName: invoice.original_filename || fetchResp.file_name || 'reprocess.pdf',
  fileExtension: 'pdf',
  fileHash: invoice.file_hash,
  fileMime: 'application/pdf',
  binaryPropertyName: 'data',
  vision_images: images,
  mimeForGpt,
  gemini_body,
  openai_body,
  _attachment_b64: fetchResp.pdf_b64,
  _attachment_mime: fetchResp.mime || 'application/pdf',
  _is_likely_screenshot: false,
  _archive_type: 'document_pdf',
  _reprocess_mode: true,
  _reprocess_attempts_prev: invoice.reprocess_attempts || 0,
  vision_failed: false
} };
